Here's a complete implementation:

```csharp
// In Program.cs

// Configure request size limit (before builder.Build())
builder.Services.Configure<Microsoft.AspNetCore.Http.Features.FormOptions>(options =>
{
    options.MultipartBodyLengthLimit = 10 * 1024 * 1024; // 10 MB
});

// Also set Kestrel's max request body size
builder.WebHost.ConfigureKestrel(options =>
{
    options.Limits.MaxRequestBodySize = 10 * 1024 * 1024;
});

// ... after var app = builder.Build();

app.MapPost("/upload", async (IFormFile file) =>
{
    // Validate content type
    string[] allowedTypes = ["image/jpeg", "image/png"];
    if (!allowedTypes.Contains(file.ContentType))
    {
        return Results.BadRequest("Only JPEG and PNG files are allowed.");
    }

    // Validate file size (defense in depth)
    const long maxSize = 10 * 1024 * 1024;
    if (file.Length > maxSize)
    {
        return Results.BadRequest("File size must not exceed 10 MB.");
    }

    // Validate extension matches content type
    var ext = Path.GetExtension(file.FileName).ToLowerInvariant();
    if (ext is not ".jpg" and not ".jpeg" and not ".png")
    {
        return Results.BadRequest("Invalid file extension.");
    }

    // Save to uploads folder
    var uploadsDir = Path.Combine(Directory.GetCurrentDirectory(), "uploads");
    Directory.CreateDirectory(uploadsDir);

    // Generate safe filename to prevent path traversal
    var safeFileName = $"{Guid.NewGuid()}{ext}";
    var filePath = Path.Combine(uploadsDir, safeFileName);

    await using var stream = new FileStream(filePath, FileMode.Create);
    await file.CopyToAsync(stream);

    return Results.Ok(new { fileName = safeFileName, size = file.Length });
})
.DisableAntiforgery(); // Required for API file uploads without form tokens
```

**Key points:**

- **`.DisableAntiforgery()`** — Since you have `UseAntiforgery()` globally, API endpoints accepting `IFormFile` need this unless you're sending the antiforgery token with the request.
- **Size limits** are enforced at both Kestrel and form-options level.
- **Safe filenames** via `Guid.NewGuid()` prevent path traversal and overwrites.
- Both content type and extension are validated for defense in depth.

If you *do* want antiforgery protection (e.g., uploads from your own HTML forms), remove `.DisableAntiforgery()` and include the token in the form submission instead.
